var syalert=function(){return{syopen:function(id){var dom=$("#"+id);this.sycenter(dom);var sylayer8=dom.hasClass('layer8'); if(sylayer8){var name="zoomIn";}else{var name="fadeInRight";} var type=dom.attr("sy-type");var mask=dom.attr("sy-mask");dom.addClass(name);dom.show();var that=this;$("body").css({"overflow-y":"hidden"});dom.append('<a href="javascript:;" class="syalertclose"></a>'); if(mask=="true"){$("body").append("<div class='sy-mask' onclick=\"closeAlert('"+id+"')\"></div>");$(".sy-mask").fadeIn(300)}setTimeout(function(){dom.removeClass(name)},300);if(type=="tips"){setTimeout(function(){that.syhide(id)},10000)}},syhide:function(id){if(typeof id=="undefined"){var dom=$(".sy-alert")}else{var dom=$("#"+id)} var sylayer8=dom.hasClass('layer8'); if(sylayer8){var name="zoomOut";}else{var name="fadeOutRight";} dom.addClass(name);$(".sy-mask").fadeOut(300);setTimeout(function(){dom.hide();dom.removeClass(name);$(".sy-mask").remove();dom.find('.syalertclose').remove();$("body").css({"overflow-y":"auto"})},300)},sycenter:function(dom){var mgtop=parseFloat(dom.height()/2);dom.css({"top":"13%","margin-top":"-"+mgtop+"px"})}}}();

$('.sy-alert').on('click','.syalertclose',function(){
	syalert.syhide('alert1');
	// console.log('1111');
})